import { IMessageComposer } from '@nitrots/nitro-renderer';

export class AcceptDoorDashOrderComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(orderId: number) {
        const id = Math.max(0, Math.floor(orderId || 0));
        this._data = [id];
        console.log(
            '[📤] AcceptDoorDashOrderComposer packet sent:',
            this._data
        );
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
